@import "tailwindcss";

@theme {
  --color-mictlan-gold: #FFD700;
  --color-mictlan-red: #DC2626;
  --color-mictlan-black: #000000;
  --color-mictlan-dark-gray: #1A1A1A;
}

:root {
  background-color: var(--color-mictlan-black);
  color: white;
}

#root {
  max-width: 1280px;
  margin: 0 auto;
  padding: 2rem;
  text-align: center;
}

.logo {
  height: 6em;
  padding: 1.5em;
  will-change: filter;
  transition: filter 300ms;
}
.logo:hover {
  filter: drop-shadow(0 0 2em #646cffaa);
}
.logo.react:hover {
  filter: drop-shadow(0 0 2em #61dafbaa);
}

@keyframes logo-spin {
  from {
    transform: rotate(0deg);
  }
  to {
    transform: rotate(360deg);
  }
}

@media (prefers-reduced-motion: no-preference) {
  a:nth-of-type(2) .logo {
    animation: logo-spin infinite 20s linear;
  }
}

.card {
  padding: 2em;
}

.read-the-docs {
  color: #888;
}

const admin = require('firebase-admin');
const serviceAccount = require('./sa-key-admin.json');

admin.initializeApp({
  credential: admin.credential.cert(serviceAccount)
});

const db = admin.firestore();

async function clearProductsCollection() {
  try {
    const collectionRef = db.collection('products');
    const snapshot = await collectionRef.get();
    
    if (snapshot.empty) {
      console.log('No documents found in "products" collection. Nothing to delete.');
      return;
    }

    const batch = db.batch();
    snapshot.docs.forEach(doc => {
      batch.delete(doc.ref);
    });
    await batch.commit();
    console.log(`Successfully deleted ${snapshot.docs.length} documents from "products" collection.`);
  } catch (error) {
    console.error('Error clearing "products" collection:', error);
  } finally {
    admin.app().delete();
  }
}

clearProductsCollection();

